-- violating: GROUP_CONCAT + ROWNUM> 恒空集 + 空串判空 + IFNULL/NOW + IDENTITY 显式赋值 + 深分页
SELECT GROUP_CONCAT(NAME) FROM ORDERS GROUP BY NAME;
SELECT * FROM ORDERS WHERE ROWNUM > 10 ORDER BY ID;
